mapper.update:
UPDATE ess_alert a
JOIN ess_device d
  ON a.device_id = d.device_id
SET a.status = #{status}
WHERE a.alert_id = #{alertId}
  AND d.member_id = #{memberId}

mapper.select:
SELECT COUNT(*)
FROM ess_alert
WHERE device_id = #{deviceId}
  AND alert_type = #{alertType}
  AND status = 'OPEN'
